#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; long long K; scanf("%lld %lld", &N, &K);
        long long base = N*(N+1)/2;
        if(K < base){
            printf("-1");
        }else{
            long long first = K - base + 1;
            printf("%lld", first);
            for(long long i=2;i<=N;i++) printf(" 1");
        }
        if(T) printf("\n");
    }
    return 0;
}

